import{_ as r,o as d,c as e,a2 as o}from"./chunks/framework.BZO4qERu.js";const g=JSON.parse('{"title":"核心概念","description":"","frontmatter":{},"headers":[],"relativePath":"rudder/01-入门/核心概念.md","filePath":"rudder/01-入门/核心概念.md","lastUpdated":1780387686000}'),a={name:"rudder/01-入门/核心概念.md"};function s(n,t,l,i,c,u){return d(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h1><h2 id="rudder-解决什么问题" tabindex="-1">Rudder 解决什么问题 <a class="header-anchor" href="#rudder-解决什么问题" aria-label="Permalink to &quot;Rudder 解决什么问题&quot;">​</a></h2><p>用过 AI 写代码的都懂——每次新会话打开，AI 就像喝了孟婆汤，一切从头来。</p><p>Rudder 做的事很简单：<strong>把项目规范、记忆、任务状态全部落盘到仓库里，每次会话自动按需注入，AI 不再&quot;失忆&quot;。</strong></p><h2 id="分层架构" tabindex="-1">分层架构 <a class="header-anchor" href="#分层架构" aria-label="Permalink to &quot;分层架构&quot;">​</a></h2><p>Rudder 不把 3000 行规则塞进一个文件，而是分层：</p><table tabindex="0"><thead><tr><th>层级</th><th>位置</th><th>作用</th></tr></thead><tbody><tr><td><strong>工作流定义</strong></td><td><code>.rudder/workflow.md</code></td><td>4 阶段循环的总纲</td></tr><tr><td><strong>Spec 规范</strong></td><td><code>.rudder/spec/</code></td><td>按作用域拆分的编码指南</td></tr><tr><td><strong>任务上下文</strong></td><td><code>.rudder/tasks/</code></td><td>每个任务的 PRD、实现记录、审查上下文</td></tr><tr><td><strong>项目记忆</strong></td><td><code>.rudder/workspace/</code></td><td>开发者工作日志，跨 session 续上下文</td></tr><tr><td><strong>平台适配</strong></td><td><code>.claude/</code> <code>.cursor/</code> <code>.codex/</code> ...</td><td>各平台自动触发的 hooks 和 agents</td></tr></tbody></table><h2 id="为什么分层" tabindex="-1">为什么分层 <a class="header-anchor" href="#为什么分层" aria-label="Permalink to &quot;为什么分层&quot;">​</a></h2><ol><li><strong>CLAUDE.md / AGENTS.md / .cursorrules 的痛点</strong>：用久了变成几千行的缝合怪，没人读</li><li><strong>Spec 按作用域拆分</strong>：前端、后端、数据库各有不同规范，不需要塞一个文件</li><li><strong>任务独立上下文</strong>：每个任务有自己的 PRD、实现记录和审查结论</li><li><strong>工作流有关卡</strong>：Plan → Implement → Verify → Finish，每个阶段有明确要求</li><li><strong>跨平台自动适配</strong>：同一套 Rudder 结构，随便切 Claude Code / Gemini / Cursor / Codex</li></ol><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><ol><li><strong>规范写好一次</strong> — 放 <code>.rudder/spec/</code> 里，Rudder 按任务自动注入相关文件</li><li><strong>一切落盘</strong> — 研究、决策、教训全写文件，对话会被压缩，文件不会</li><li><strong>增量开发</strong> — 一个任务一个任务来</li><li><strong>沉淀认知</strong> — 每个任务结束后，把新认知写回 Spec</li></ol><h2 id="谁在用" tabindex="-1">谁在用 <a class="header-anchor" href="#谁在用" aria-label="Permalink to &quot;谁在用&quot;">​</a></h2><ul><li><strong>个人开发者</strong>：项目记忆 + 可复用工作流</li><li><strong>团队</strong>：标准统一、任务边界清晰、上下文可审查、换平台不换脑子</li><li><strong>Java 全栈工程师</strong>：Rudder 作者本人是 Java 全栈开发，日常自用迭代，Java spec 模板最丰富；同时其他语言也完全兼容</li></ul>',13)])])}const p=r(a,[["render",s]]);export{g as __pageData,p as default};
